     1→/**
     2→ * Cross-Platform Utilities for PAI v2.5
     3→ *
     4→ * Provides platform detection and platform-specific helpers
     5→ * for Windows, macOS, and Linux.
     6→ */
     7→
     8→import * as os from 'os';
     9→import * as path from 'path';
    10→
    11→// ============================================================================
    12→// PLATFORM DETECTION
    13→// ============================================================================
    14→
    15→export const PLATFORM = process.platform;
    16→export const IS_WINDOWS = PLATFORM === 'win32';
    17→export const IS_MAC = PLATFORM === 'darwin';
    18→export const IS_LINUX = PLATFORM === 'linux';
    19→
    20→// ============================================================================
    21→// PATHS
    22→// ============================================================================
    23→
    24→export const HOME = IS_WINDOWS
    25→  ? process.env.USERPROFILE || os.homedir()
    26→  : process.env.HOME || os.homedir();
    27→
    28→export const CLAUDE_DIR = path.join(HOME, '.claude');
    29→
    30→export const DEFAULT_PROJECTS_DIR = path.join(HOME, 'Projects');
    31→
    32→// ============================================================================
    33→// PLATFORM-SPECIFIC PATHS
    34→// ============================================================================
    35→
    36→export function getHome(): string {
    37→  return HOME;
    38→}
    39→
    40→export function getClaudeDir(): string {
    41→  return CLAUDE_DIR;
    42→}
    43→
    44→export function getProjectsDir(projectsDir?: string): string {
    45→  return projectsDir || DEFAULT_PROJECTS_DIR;
    46→}
    47→
    48→// ============================================================================
    49→// COMMAND MAPPING
    50→// ============================================================================
    51→
    52→/**
    53→ * Map Unix commands to Windows equivalents
    54→ */
    55→export function getCommand(command: string): string {
    56→  const commandMap: Record<string, string> = {
    57→    'ls': IS_WINDOWS ? 'dir' : 'ls',
    58→    'cat': IS_WINDOWS ? 'type' : 'cat',
    59→    'rm': IS_WINDOWS ? 'del' : 'rm',
    60→    'cp': IS_WINDOWS ? 'copy' : 'cp',
    61→    'mv': IS_WINDOWS ? 'move' : 'mv',
    62→    'ps': IS_WINDOWS ? 'tasklist' : 'ps',
    63→    'kill': IS_WINDOWS ? 'taskkill' : 'kill',
    64→    'pwd': IS_WINDOWS ? 'cd' : 'pwd',
    65→    'clear': IS_WINDOWS ? 'cls' : 'clear',
    66→    'echo': 'echo', // Same on all platforms
    67→    'mkdir': IS_WINDOWS ? 'mkdir' : 'mkdir', // Same but flags differ
    68→    'rmdir': IS_WINDOWS ? 'rmdir' : 'rmdir',
    69→  };
    70→
    71→  return commandMap[command] || command;
    72→}
    73→
    74→/**
    75→ * Get command arguments for platform
    76→ */
    77→export function getCommandArgs(command: string, args: string[]): string[] {
    78→  if (IS_WINDOWS) {
    79→    // Windows-specific argument adjustments
    80→    if (command === 'mkdir' && !args.includes('/p')) {
    81→      // Unix: mkdir -p → Windows: mkdir (already creates parents)
    82→      return args.filter(arg => arg !== '-p');
    83→    }
    84→  }
    85→
    86→  return args;
    87→}
    88→
    89→// ============================================================================
    90→// SHELL CONFIGURATION
    91→// ============================================================================
    92→
    93→export interface ShellConfig {
    94→  shell: string;
    95→  profile: string;
    96→  configCmd: string;
    97→}
    98→
    99→export function getShellConfig(): ShellConfig {
   100→  if (IS_WINDOWS) {
   101→    return {
   102→      shell: 'powershell',
   103→      profile: path.join(HOME, 'Documents', 'PowerShell', 'Microsoft.PowerShell_profile.ps1'),
   104→      configCmd: 'pwsh',
   105→    };
   106→  } else if (IS_MAC) {
   107→    return {
   108→      shell: 'zsh',
   109→      profile: path.join(HOME, '.zshrc'),
   110→      configCmd: 'zsh',
   111→    };
   112→  } else {
   113→    // Linux - try zsh first, fallback to bash
   114→    const zshrc = path.join(HOME, '.zshrc');
   115→    const hasZsh = require('fs').existsSync(zshrc);
   116→
   117→    return {
   118→      shell: hasZsh ? 'zsh' : 'bash',
   119→      profile: hasZsh ? zshrc : path.join(HOME, '.bashrc'),
   120→      configCmd: hasZsh ? 'zsh' : 'bash',
   121→    };
   122→  }
   123→}
   124→
   125→// ============================================================================
   126→// FILE OPERATIONS
   127→// ============================================================================
   128→
   129→/**
   130→ * Check if path is absolute
   131→ */
   132→export function isAbsolute(p: string): boolean {
   133→  return path.isAbsolute(p);
   134→}
   135→
   136→/**
   137→ * Normalize path for current platform
   138→ */
   139→export function normalizePath(p: string): string {
   140→  return path.normalize(p);
   141→}
   142→
   143→/**
   144→ * Join path segments
   145→ */
   146→export function joinPaths(...segments: string[]): string {
   147→  return path.join(...segments);
   148→}
   149→
   150→// ============================================================================
   151→// PERMISSIONS
   152→// ============================================================================
   153→
   154→/**
   155→ * Set executable permission on file
   156→ * (No-op on Windows, chmod +x on Unix)
   157→ */
   158→export function setExecutable(filePath: string): void {
   159→  if (!IS_WINDOWS) {
   160→    const { execSync } = require('child_process');
   161→    try {
   162→      execSync(`chmod +x "${filePath}"`, { stdio: 'pipe' });
   163→    } catch (e) {
   164→      // Ignore errors
   165→    }
   166→  }
   167→}
   168→
   169→/**
   170→ * Set directory permissions
   171→ */
   172→export function setDirectoryPermissions(dirPath: string): void {
   173→  if (IS_WINDOWS) {
   174→    // Windows: Use icacls
   175→    const { execSync } = require('child_process');
   176→    const { userInfo } = require('os');
   177→    const username = userInfo().username;
   178→
   179→    try {
   180→      execSync(`icacls "${dirPath}" /grant "${username}:(OI)(CI)F" /T`, {
   181→        stdio: 'pipe',
   182→        shell: true,
   183→      });
   184→    } catch (e) {
   185→      // Ignore errors - default permissions usually OK
   186→    }
   187→  } else {
   188→    // Unix: chmod + chown
   189→    const { execSync } = require('child_process');
   190→    const { userInfo } = require('os');
   191→    const info = userInfo();
   192→
   193→    try {
   194→      execSync(`chmod -R 755 "${dirPath}"`, { stdio: 'pipe' });
   195→      execSync(`chown -R ${info.uid}:${info.gid} "${dirPath}"`, { stdio: 'pipe' });
   196→    } catch (e) {
   197→      // Ignore errors
   198→    }
   199→  }
   200→}
   201→
   202→// ============================================================================
   203→// PROCESS MANAGEMENT
   204→// ============================================================================
   205→
   206→/**
   207→ * Find process using port
   208→ */
   209→export function findProcessOnPort(port: number): number[] {
   210→  const { execSync } = require('child_process');
   211→
   212→  try {
   213→    if (IS_WINDOWS) {
   214→      const result = execSync(`netstat -ano | findstr :${port}`, {
   215→        encoding: 'utf-8',
   216→        stdio: ['pipe', 'pipe', 'pipe'],
   217→      });
   218→
   219→      const pids: number[] = [];
   220→      const lines = result.trim().split('\n');
   221→
   222→      for (const line of lines) {
   223→        const parts = line.trim().split(/\s+/);
   224→        const pid = parseInt(parts[parts.length - 1]);
   225→        if (!isNaN(pid)) {
   226→          pids.push(pid);
   227→        }
   228→      }
   229→
   230→      return [...new Set(pids)]; // Unique PIDs
   231→    } else {
   232→      const result = execSync(`lsof -ti:${port}`, {
   233→        encoding: 'utf-8',
   234→        stdio: ['pipe', 'pipe', 'pipe'],
   235→      });
   236→
   237→      return result
   238→        .trim()
   239→        .split('\n')
   240→        .map((s: string) => parseInt(s.trim()))
   241→        .filter((n: number) => !isNaN(n));
   242→    }
   243→  } catch (e) {
   244→    return [];
   245→  }
   246→}
   247→
   248→/**
   249→ * Kill process by PID
   250→ */
   251→export function killProcess(pid: number): boolean {
   252→  const { execSync } = require('child_process');
   253→
   254→  try {
   255→    if (IS_WINDOWS) {
   256→      execSync(`taskkill /F /PID ${pid}`, { stdio: 'pipe' });
   257→    } else {
   258→      execSync(`kill -9 ${pid}`, { stdio: 'pipe' });
   259→    }
   260→    return true;
   261→  } catch (e) {
   262→    return false;
   263→  }
   264→}
   265→
   266→// ============================================================================
   267→// AUDIO PLAYBACK
   268→// ============================================================================
   269→
   270→export interface AudioConfig {
   271→  platform: string;
   272→  player: string;
   273→  volumeScale: number;
   274→}
   275→
   276→export function getAudioConfig(): AudioConfig {
   277→  if (IS_WINDOWS) {
   278→    return {
   279→      platform: 'windows',
   280→      player: 'powershell',
   281→      volumeScale: 1.0, // 0.0 to 1.0
   282→    };
   283→  } else if (IS_MAC) {
   284→    return {
   285→      platform: 'macos',
   286→      player: 'afplay',
   287→      volumeScale: 1.0, // 0.0 to 1.0
   288→    };
   289→  } else {
   290→    return {
   291→      platform: 'linux',
   292→      player: 'paplay', // or aplay
   293→      volumeScale: 65536, // 0 to 65536
   294→    };
   295→  }
   296→}
   297→
   298→// ============================================================================
   299→// LOGGING
   300→// ============================================================================
   301→
   302→/**
   303→ * Get log directory for platform
   304→ */
   305→export function getLogDir(appName: string = 'PAI'): string {
   306→  if (IS_WINDOWS) {
   307→    return path.join(HOME, 'AppData', 'Local', appName, 'logs');
   308→  } else if (IS_MAC) {
   309→    return path.join(HOME, 'Library', 'Logs', appName);
   310→  } else {
   311→    // Linux
   312→    const xdgDataHome = process.env.XDG_DATA_HOME || path.join(HOME, '.local', 'share');
   313→    return path.join(xdgDataHome, appName, 'logs');
   314→  }
   315→}
   316→
   317→// ============================================================================
   318→// ENVIRONMENT
   319→// ============================================================================
   320→
   321→/**
   322→ * Get PATH environment variable delimiter
   323→ */
   324→export function getPathDelimiter(): string {
   325→  return IS_WINDOWS ? ';' : ':';
   326→}
   327→
   328→/**
   329→ * Add to PATH
   330→ */
   331→export function addToPath(dirToAdd: string): void {
   332→  const delimiter = getPathDelimiter();
   333→  const pathEnv = process.env.PATH || '';
   334→
   335→  if (!pathEnv.includes(dirToAdd)) {
   336→    process.env.PATH = `${dirToAdd}${delimiter}${pathEnv}`;
   337→  }
   338→}
   339→
   340→// ============================================================================
   341→// TROUBLESHOOTING HELPERS
   342→// ============================================================================
   343→
   344→/**
   345→ * Get platform-specific troubleshooting info
   346→ */
   347→export function getTroubleshootingInfo(): string {
   348→  if (IS_WINDOWS) {
   349→    return `
   350→Windows Troubleshooting:
   351→- Run PowerShell as Administrator for permission issues
   352→- Enable Long Paths: New-ItemProperty -Path "HKLM:\\SYSTEM\\CurrentControlSet\\Control\\FileSystem" -Name "LongPathsEnabled" -Value 1 -PropertyType DWORD -Force
   353→- Set Execution Policy: Set-ExecutionPolicy -ExecutionPolicy RemoteSigned -Scope CurrentUser
   354→- Check PATH: echo $env:PATH
   355→`;
   356→  } else if (IS_MAC) {
   357→    return `
   358→macOS Troubleshooting:
   359→- Install Xcode Command Line Tools: xcode-select --install
   360→- Fix permissions: sudo chown -R $(whoami) ~/.claude
   361→- Check shell: echo $SHELL
   362→`;
   363→  } else {
   364→    return `
   365→Linux Troubleshooting:
   366→- Fix permissions: sudo chown -R $(whoami) ~/.claude
   367→- Check dependencies: python3, node, git
   368→- Install missing packages via your package manager (apt, yum, dnf, etc.)
   369→`;
   370→  }
   371→}
   372→
   373→// ============================================================================
   374→// EXPORTS
   375→// ============================================================================
   376→
   377→export default {
   378→  PLATFORM,
   379→  IS_WINDOWS,
   380→  IS_MAC,
   381→  IS_LINUX,
   382→  HOME,
   383→  CLAUDE_DIR,
   384→  DEFAULT_PROJECTS_DIR,
   385→  getHome,
   386→  getClaudeDir,
   387→  getProjectsDir,
   388→  getCommand,
   389→  getCommandArgs,
   390→  getShellConfig,
   391→  isAbsolute,
   392→  normalizePath,
   393→  joinPaths,
   394→  setExecutable,
   395→  setDirectoryPermissions,
   396→  findProcessOnPort,
   397→  killProcess,
   398→  getAudioConfig,
   399→  getLogDir,
   400→  getPathDelimiter,
   401→  addToPath,
   402→  getTroubleshootingInfo,
   403→};
