     1→#!/usr/bin/env bun
     2→/**
     3→ * AutoWorkCreation.hook.ts - Session/Task Management (UserPromptSubmit)
     4→ *
     5→ * PURPOSE:
     6→ * Creates and manages the session/task hierarchy for each Claude Code session.
     7→ * - SESSION: One directory per Claude Code session (the primitive)
     8→ * - TASK: Subdirectories for distinct work items within a session
     9→ *
    10→ * Each task has its own algorithm execution context (ISC.json, THREAD.md).
    11→ *
    12→ * TRIGGER: UserPromptSubmit
    13→ *
    14→ * STRUCTURE CREATED:
    15→ * WORK/{timestamp}_{session-title}/
    16→ * ├── META.yaml                    # Session metadata
    17→ * ├── tasks/
    18→ * │   ├── 001_{task-slug}/
    19→ * │   │   ├── ISC.json             # Task's Ideal State Criteria
    20→ * │   │   └── THREAD.md            # Task's algorithm log (includes metadata in frontmatter)
    21→ * │   └── current -> 001_...       # Symlink to active task
    22→ * └── scratch/                     # Temporary files
    23→ */
    24→
    25→import { mkdirSync, existsSync, readFileSync, writeFileSync, symlinkSync, unlinkSync, lstatSync } from 'fs';
    26→import { join } from 'path';
    27→import { getPSTComponents, getISOTimestamp } from './lib/time';
    28→import { inference } from '../skills/PAI/Tools/Inference';
    29→import { PLATFORM } from './lib/platform-paths';
    30→import { getPaiDir } from './lib/paths';
    31→
    32→interface HookInput {
    33→  session_id: string;
    34→  prompt?: string;
    35→  user_prompt?: string;
    36→}
    37→
    38→interface CurrentWork {
    39→  session_id: string;
    40→  session_dir: string;
    41→  current_task: string;
    42→  task_count: number;
    43→  created_at: string;
    44→}
    45→
    46→interface PromptClassification {
    47→  type: 'work' | 'question' | 'conversational';
    48→  title: string;
    49→  effort: 'TRIVIAL' | 'QUICK' | 'STANDARD' | 'THOROUGH';
    50→  is_new_topic: boolean;
    51→}
    52→
    53→// Cross-platform path resolution using getPaiDir from lib/paths
    54→const BASE_DIR = getPaiDir();
    55→const WORK_DIR = join(BASE_DIR, 'MEMORY', 'WORK');
    56→const STATE_DIR = join(BASE_DIR, 'MEMORY', 'STATE');
    57→const CURRENT_WORK_FILE = join(STATE_DIR, 'current-work.json');
    58→
    59→const CLASSIFICATION_PROMPT = `Classify this user request. Return ONLY valid JSON:
    60→{
    61→  "type": "work" | "question" | "conversational",
    62→  "title": "<3-8 word title>",
    63→  "effort": "TRIVIAL" | "QUICK" | "STANDARD" | "THOROUGH",
    64→  "is_new_topic": true | false
    65→}
    66→
    67→DEFINITIONS:
    68→- type: work (task/imperative), question (info request), conversational (greeting/thanks)
    69→- effort: TRIVIAL (<5 min), QUICK (5-30 min), STANDARD (30 min - 2 hrs), THOROUGH (2+ hrs)
    70→- is_new_topic: true if this is a distinctly different topic from previous context, false if continuation
    71→
    72→CONTEXT FOR is_new_topic:
    73→- true: "Now let's work on authentication" (new domain)
    74→- true: "Different question - how do I..." (explicit topic change)
    75→- false: "Also update the..." (continuation)
    76→- false: "What about..." (follow-up on same topic)
    77→- false: "Proceed" or "Yes" (confirmation)`;
    78→
    79→async function readStdinWithTimeout(timeout: number = 5000): Promise<string> {
    80→  return new Promise((resolve, reject) => {
    81→    let data = '';
    82→    const timer = setTimeout(() => reject(new Error('Timeout')), timeout);
    83→    process.stdin.on('data', (chunk) => { data += chunk.toString(); });
    84→    process.stdin.on('end', () => { clearTimeout(timer); resolve(data); });
    85→    process.stdin.on('error', (err) => { clearTimeout(timer); reject(err); });
    86→  });
    87→}
    88→
    89→function readCurrentWork(): CurrentWork | null {
    90→  try {
    91→    if (!existsSync(CURRENT_WORK_FILE)) return null;
    92→    return JSON.parse(readFileSync(CURRENT_WORK_FILE, 'utf-8'));
    93→  } catch {
    94→    return null;
    95→  }
    96→}
    97→
    98→function writeCurrentWork(state: CurrentWork): void {
    99→  if (!existsSync(STATE_DIR)) mkdirSync(STATE_DIR, { recursive: true });
   100→  writeFileSync(CURRENT_WORK_FILE, JSON.stringify(state, null, 2), 'utf-8');
   101→}
   102→
   103→function slugify(text: string, maxLen: number = 40): string {
   104→  return text
   105→    .toLowerCase()
   106→    .replace(/[^a-z0-9\s-]/g, '')
   107→    .replace(/\s+/g, '-')
   108→    .replace(/-+/g, '-')
   109→    .substring(0, maxLen)
   110→    .replace(/-$/, '') || 'task';
   111→}
   112→
   113→function generateSessionDirName(title: string): string {
   114→  const { year, month, day, hours, minutes, seconds } = getPSTComponents();
   115→  const timestamp = `${year}${month}${day}-${hours}${minutes}${seconds}`;
   116→  return `${timestamp}_${slugify(title, 50)}`;
   117→}
   118→
   119→/**
   120→ * Create session directory structure
   121→ */
   122→function createSessionDirectory(sessionDirName: string, sessionId: string, title: string): string {
   123→  const sessionPath = join(WORK_DIR, sessionDirName);
   124→  const timestamp = getISOTimestamp();
   125→
   126→  // Create session structure
   127→  mkdirSync(join(sessionPath, 'tasks'), { recursive: true });
   128→  mkdirSync(join(sessionPath, 'scratch'), { recursive: true });
   129→
   130→  // Session META.yaml
   131→  const meta = `id: "${sessionDirName}"
   132→title: "${title}"
   133→session_id: "${sessionId}"
   134→created_at: "${timestamp}"
   135→status: "ACTIVE"
   136→`;
   137→  writeFileSync(join(sessionPath, 'META.yaml'), meta, 'utf-8');
   138→
   139→  console.error(`[AutoWork] Created session: ${sessionPath}`);
   140→  return sessionPath;
   141→}
   142→
   143→/**
   144→ * Create task directory with ISC.json and THREAD.md (with frontmatter metadata)
   145→ */
   146→function createTaskDirectory(
   147→  sessionPath: string,
   148→  taskNumber: number,
   149→  title: string,
   150→  effort: string,
   151→  prompt: string
   152→): string {
   153→  const taskId = String(taskNumber).padStart(3, '0');
   154→  const taskSlug = slugify(title);
   155→  const taskDirName = `${taskId}_${taskSlug}`;
   156→  const taskPath = join(sessionPath, 'tasks', taskDirName);
   157→  const timestamp = getISOTimestamp();
   158→
   159→  mkdirSync(taskPath, { recursive: true });
   160→
   161→  // Task THREAD.md with frontmatter metadata (no separate META.yaml)
   162→  const thread = `---
   163→taskId: "${taskDirName}"
   164→title: "${title}"
   165→effortLevel: "${effort}"
   166→status: "IN_PROGRESS"
   167→createdAt: "${timestamp}"
   168→prompt: |
   169→  ${prompt.substring(0, 500).replace(/\n/g, '\n  ')}
   170→---
   171→
   172→# Algorithm Thread: ${title}
   173→
   174→## Phase Log
   175→
   176→### 👀 OBSERVE Phase
   177→_Pending..._
   178→
   179→### 🧠 THINK Phase
   180→_Pending..._
   181→
   182→### 📋 PLAN Phase
   183→_Pending..._
   184→
   185→### 🔨 BUILD Phase
   186→_Pending..._
   187→
   188→### ▶️ EXECUTE Phase
   189→_Pending..._
   190→
   191→### ✅ VERIFY Phase
   192→_Pending..._
   193→
   194→### 🎓 LEARN Phase
   195→_Pending..._
   196→
   197→---
   198→
   199→## ISC Evolution
   200→
   201→_Criteria updates logged here..._
   202→
   203→---
   204→
   205→## Key Observations
   206→
   207→_Important observations during execution..._
   208→`;
   209→  writeFileSync(join(taskPath, 'THREAD.md'), thread, 'utf-8');
   210→
   211→  // Task ISC.json with proper scaffold
   212→  const isc = {
   213→    taskId: taskDirName,
   214→    status: 'PENDING',
   215→    effortLevel: effort,
   216→    criteria: [],
   217→    antiCriteria: [],
   218→    satisfaction: null,
   219→    createdAt: timestamp,
   220→    updatedAt: timestamp,
   221→  };
   222→  writeFileSync(join(taskPath, 'ISC.json'), JSON.stringify(isc, null, 2), 'utf-8');
   223→
   224→  // Update 'current' symlink (or directory junction on Windows)
   225→  const currentLink = join(sessionPath, 'tasks', 'current');
   226→  try {
   227→    if (existsSync(currentLink) || lstatSync(currentLink)) {
   228→      unlinkSync(currentLink);
   229→    }
   230→  } catch { /* ignore if doesn't exist */ }
   231→
   232→  // On Windows, create a junction. On Unix, create a symlink.
   233→  try {
   234→    symlinkSync(taskDirName, currentLink, PLATFORM === 'win32' ? 'junction' : undefined);
   235→  } catch (err) {
   236→    // If symlink/junction fails, copy as fallback
   237→    console.error('[AutoWork] Symlink/junction failed, copying directory:', err);
   238→    // Could implement copy fallback here if needed
   239→  }
   240→
   241→  console.error(`[AutoWork] Created task: ${taskPath}`);
   242→  return taskDirName;
   243→}
   244→
   245→async function classifyPrompt(prompt: string, hasExistingSession: boolean): Promise<PromptClassification> {
   246→  const trimmed = prompt.trim();
   247→
   248→  // Quick heuristics
   249→  if (trimmed.length < 15 && /^(yes|no|ok|okay|thanks|proceed|continue|go ahead|sure|got it)$/i.test(trimmed)) {
   250→    return { type: 'conversational', title: '', effort: 'TRIVIAL', is_new_topic: false };
   251→  }
   252→
   253→  // Use inference for classification
   254→  try {
   255→    const contextNote = hasExistingSession
   256→      ? '\n\nNOTE: There is an existing session with prior tasks. Consider if this is a continuation or new topic.'
   257→      : '\n\nNOTE: This is the first prompt in a new session. is_new_topic should be true.';
   258→
   259→    const result = await inference({
   260→      systemPrompt: CLASSIFICATION_PROMPT + contextNote,
   261→      userPrompt: prompt,
   262→      expectJson: true,
   263→      timeout: 10000,
   264→      level: 'fast',
   265→    });
   266→
   267→    if (result.success && result.parsed) {
   268→      const parsed = result.parsed as PromptClassification;
   269→      return {
   270→        type: parsed.type || 'work',
   271→        title: parsed.title || prompt.substring(0, 50),
   272→        effort: parsed.effort || 'STANDARD',
   273→        is_new_topic: hasExistingSession ? (parsed.is_new_topic ?? false) : true,
   274→      };
   275→    }
   276→  } catch (err) {
   277→    console.error(`[AutoWork] Classification failed: ${err}`);
   278→  }
   279→
   280→  // Fallback
   281→  return {
   282→    type: 'work',
   283→    title: prompt.substring(0, 50).replace(/[^a-zA-Z0-9\s]/g, '').trim(),
   284→    effort: 'STANDARD',
   285→    is_new_topic: !hasExistingSession,
   286→  };
   287→}
   288→
   289→async function main() {
   290→  try {
   291→    const input = await readStdinWithTimeout();
   292→    const data: HookInput = JSON.parse(input);
   293→    const prompt = data.prompt || data.user_prompt || '';
   294→    const sessionId = data.session_id || 'unknown';
   295→
   296→    if (!prompt || prompt.length < 2) {
   297→      process.exit(0);
   298→    }
   299→
   300→    if (!existsSync(WORK_DIR)) mkdirSync(WORK_DIR, { recursive: true });
   301→
   302→    let currentWork = readCurrentWork();
   303→    const isExistingSession = currentWork && currentWork.session_id === sessionId;
   304→
   305→    const classification = await classifyPrompt(prompt, !!isExistingSession);
   306→
   307→    // Skip task creation for pure conversational
   308→    if (classification.type === 'conversational' && !classification.is_new_topic) {
   309→      console.error('[AutoWork] Conversational continuation, no new task');
   310→      process.exit(0);
   311→    }
   312→
   313→    if (!isExistingSession) {
   314→      // New session: create session directory + first task
   315→      const title = classification.title || prompt.substring(0, 50);
   316→      const sessionDirName = generateSessionDirName(title);
   317→      const sessionPath = createSessionDirectory(sessionDirName, sessionId, title);
   318→
   319→      const taskDirName = createTaskDirectory(
   320→        sessionPath,
   321→        1,
   322→        title,
   323→        classification.effort,
   324→        prompt
   325→      );
   326→
   327→      currentWork = {
   328→        session_id: sessionId,
   329→        session_dir: sessionDirName,
   330→        current_task: taskDirName,
   331→        task_count: 1,
   332→        created_at: getISOTimestamp(),
   333→      };
   334→      writeCurrentWork(currentWork);
   335→
   336→      console.error(`[AutoWork] New session with task: ${taskDirName}`);
   337→    } else if (classification.is_new_topic) {
   338→      // Existing session, new topic: create new task
   339→      const sessionPath = join(WORK_DIR, currentWork!.session_dir);
   340→      const newTaskNumber = currentWork!.task_count + 1;
   341→      const title = classification.title || prompt.substring(0, 50);
   342→
   343→      const taskDirName = createTaskDirectory(
   344→        sessionPath,
   345→        newTaskNumber,
   346→        title,
   347→        classification.effort,
   348→        prompt
   349→      );
   350→
   351→      currentWork!.current_task = taskDirName;
   352→      currentWork!.task_count = newTaskNumber;
   353→      writeCurrentWork(currentWork!);
   354→
   355→      console.error(`[AutoWork] New task in session: ${taskDirName}`);
   356→    } else {
   357→      // Continuation of current task - no new task needed
   358→      console.error(`[AutoWork] Continuing task: ${currentWork!.current_task}`);
   359→    }
   360→
   361→    process.exit(0);
   362→  } catch (err) {
   363→    console.error(`[AutoWork] Error: ${err}`);
   364→    process.exit(0);
   365→  }
   366→}
   367→
   368→main();
