     1→#!/usr/bin/env bun
     2→/**
     3→ * WorkCompletionLearning.hook.ts - Extract Learnings from Completed Work (SessionEnd)
     4→ *
     5→ * PURPOSE:
     6→ * Bridges the WORK/ system to the LEARNING/ system. When a session ends with
     7→ * significant work completed, this hook captures the work metadata (files changed,
     8→ * tools used, ideal state criteria) and creates a learning file for future reference.
     9→ * This ensures insights compound over time rather than being lost.
    10→ *
    11→ * TRIGGER: SessionEnd
    12→ *
    13→ * INPUT:
    14→ * - stdin: Hook input JSON (session_id, transcript_path)
    15→ * - Files: MEMORY/STATE/current-work.json, MEMORY/WORK/<dir>/META.yaml
    16→ *
    17→ * OUTPUT:
    18→ * - stdout: None
    19→ * - stderr: Status messages
    20→ * - exit(0): Always (non-blocking)
    21→ *
    22→ * SIDE EFFECTS:
    23→ * - Creates: MEMORY/LEARNING/<category>/<YYYY-MM>/<datetime>_work_<slug>.md
    24→ * - Reads: Current work state and work directory metadata
    25→ *
    26→ * INTER-HOOK RELATIONSHIPS:
    27→ * - DEPENDS ON: AutoWorkCreation (expects WORK/ structure)
    28→ * - COORDINATES WITH: SessionSummary (both run at SessionEnd)
    29→ * - MUST RUN BEFORE: SessionSummary (captures before state is cleared)
    30→ * - MUST RUN AFTER: Stop handlers (captures completed work)
    31→ *
    32→ * SIGNIFICANT WORK CRITERIA:
    33→ * A learning is only captured if:
    34→ * - Files were changed, OR
    35→ * - Multiple items exist in work directory, OR
    36→ * - Work was manually created (source: MANUAL)
    37→ *
    38→ * LEARNING CATEGORIES:
    39→ * - ALGORITHM: Insights about process/approach improvement
    40→ * - SYSTEM: Technical system improvements
    41→ * (Determined by getLearningCategory utility)
    42→ *
    43→ * ERROR HANDLING:
    44→ * - No active work: Silent exit
    45→ * - Missing META.yaml: Silent exit
    46→ * - Write failures: Logged to stderr, silent exit
    47→ *
    48→ * PERFORMANCE:
    49→ * - Non-blocking: Yes (fire-and-forget at session end)
    50→ * - Typical execution: <100ms
    51→ */
    52→
    53→import { writeFileSync, existsSync, readFileSync, mkdirSync } from 'fs';
    54→import { join, dirname } from 'path';
    55→import { getISOTimestamp, getPSTDate } from './lib/time';
    56→import { getLearningCategory } from './lib/learning-utils';
    57→import { getPaiDir } from './lib/paths';
    58→
    59→const PAI_DIR = getPaiDir();
    60→const MEMORY_DIR = join(PAI_DIR, 'MEMORY');
    61→const STATE_DIR = join(MEMORY_DIR, 'STATE');
    62→const CURRENT_WORK_FILE = join(STATE_DIR, 'current-work.json');
    63→const WORK_DIR = join(MEMORY_DIR, 'WORK');
    64→const LEARNING_DIR = join(MEMORY_DIR, 'LEARNING');
    65→
    66→interface CurrentWork {
    67→  session_id: string;
    68→  work_dir: string;
    69→  created_at: string;
    70→  item_count: number;
    71→}
    72→
    73→interface WorkMeta {
    74→  id: string;
    75→  title: string;
    76→  created_at: string;
    77→  completed_at: string | null;
    78→  source: string;
    79→  status: string;
    80→  session_id: string;
    81→  lineage: {
    82→    tools_used: string[];
    83→    files_changed: string[];
    84→    agents_spawned: string[];
    85→  };
    86→}
    87→
    88→function parseYaml(content: string): WorkMeta {
    89→  // Simple YAML parser for our specific format
    90→  const meta: any = {};
    91→  const lines = content.split('\n');
    92→  let currentKey = '';
    93→  let inArray = false;
    94→  let arrayKey = '';
    95→
    96→  for (const line of lines) {
    97→    const trimmed = line.trim();
    98→    if (!trimmed || trimmed.startsWith('#')) continue;
    99→
   100→    // Handle array items
   101→    if (trimmed.startsWith('- ') && inArray) {
   102→      const value = trimmed.slice(2).replace(/^["']|["']$/g, '');
   103→      if (arrayKey === 'lineage') {
   104→        // Nested array in lineage
   105→        const lastKey = Object.keys(meta.lineage).pop();
   106→        if (lastKey) meta.lineage[lastKey].push(value);
   107→      } else {
   108→        meta[arrayKey].push(value);
   109→      }
   110→      continue;
   111→    }
   112→
   113→    // Handle key: value pairs
   114→    const match = trimmed.match(/^([a-z_]+):\s*(.*)$/);
   115→    if (match) {
   116→      const [, key, value] = match;
   117→      currentKey = key;
   118→
   119→      if (key === 'lineage') {
   120→        meta.lineage = { tools_used: [], files_changed: [], agents_spawned: [] };
   121→        inArray = false;
   122→        continue;
   123→      }
   124→
   125→      if (value === '[]') {
   126→        if (meta.lineage) {
   127→          meta.lineage[key] = [];
   128→        } else {
   129→          meta[key] = [];
   130→        }
   131→        inArray = false;
   132→      } else if (value === '') {
   133→        if (meta.lineage && ['tools_used', 'files_changed', 'agents_spawned'].includes(key)) {
   134→          meta.lineage[key] = [];
   135→          arrayKey = 'lineage';
   136→          inArray = true;
   137→        } else {
   138→          meta[key] = [];
   139→          arrayKey = key;
   140→          inArray = true;
   141→        }
   142→      } else {
   143→        const cleanValue = value.replace(/^["']|["']$/g, '');
   144→        if (meta.lineage && ['tools_used', 'files_changed', 'agents_spawned'].includes(key)) {
   145→          meta.lineage[key] = cleanValue === 'null' ? [] : [cleanValue];
   146→        } else {
   147→          meta[key] = cleanValue === 'null' ? null : cleanValue;
   148→        }
   149→        inArray = false;
   150→      }
   151→    }
   152→  }
   153→
   154→  return meta as WorkMeta;
   155→}
   156→
   157→function getMonthDir(category: 'SYSTEM' | 'ALGORITHM'): string {
   158→  const now = new Date();
   159→  const year = now.getFullYear();
   160→  const month = String(now.getMonth() + 1).padStart(2, '0');
   161→
   162→  const monthDir = join(LEARNING_DIR, category, `${year}-${month}`);
   163→
   164→  if (!existsSync(monthDir)) {
   165→    mkdirSync(monthDir, { recursive: true });
   166→  }
   167→
   168→  return monthDir;
   169→}
   170→
   171→function writeLearning(workMeta: WorkMeta, idealContent: string): void {
   172→  const category = getLearningCategory(workMeta.title);
   173→  const monthDir = getMonthDir(category);
   174→
   175→  const dateStr = getPSTDate();
   176→  const timeStr = new Date().toISOString().split('T')[1].slice(0, 5).replace(':', '');
   177→  const titleSlug = workMeta.title
   178→    .toLowerCase()
   179→    .replace(/[^a-z0-9]+/g, '-')
   180→    .slice(0, 30);
   181→
   182→  const filename = `${dateStr}_${timeStr}_work_${titleSlug}.md`;
   183→  const filepath = join(monthDir, filename);
   184→
   185→  // Don't overwrite existing learnings
   186→  if (existsSync(filepath)) {
   187→    console.error(`[WorkCompletionLearning] Learning already exists: ${filename}`);
   188→    return;
   189→  }
   190→
   191→  // Calculate session duration
   192→  let duration = 'Unknown';
   193→  if (workMeta.created_at && workMeta.completed_at) {
   194→    const start = new Date(workMeta.created_at);
   195→    const end = new Date(workMeta.completed_at);
   196→    const minutes = Math.round((end.getTime() - start.getTime()) / 60000);
   197→    if (minutes < 60) {
   198→      duration = `${minutes} minutes`;
   199→    } else {
   200→      const hours = Math.floor(minutes / 60);
   201→      const mins = minutes % 60;
   202→      duration = `${hours}h ${mins}m`;
   203→    }
   204→  }
   205→
   206→  const content = `# Work Completion Learning
   207→
   208→**Title:** ${workMeta.title}
   209→**Duration:** ${duration}
   210→**Category:** ${category}
   211→**Session:** ${workMeta.session_id}
   212→
   213→---
   214→
   215→## Ideal State Criteria
   216→
   217→${idealContent || 'Not specified'}
   218→
   219→## What Was Done
   220→
   221→- **Files Changed:** ${workMeta.lineage?.files_changed?.length || 0}
   222→- **Tools Used:** ${workMeta.lineage?.tools_used?.join(', ') || 'None tracked'}
   223→- **Agents Spawned:** ${workMeta.lineage?.agents_spawned?.length || 0}
   224→
   225→## Insights
   226→
   227→*This work session completed successfully. Consider what made it effective:*
   228→
   229→- Was the approach straightforward or did it require iteration?
   230→- Were there any blockers or surprises?
   231→- What patterns from this work apply to future tasks?
   232→
   233→---
   234→
   235→*Auto-captured by WorkCompletionLearning hook at session end*
   236→`;
   237→
   238→  writeFileSync(filepath, content);
   239→  console.error(`[WorkCompletionLearning] Created learning: ${filename}`);
   240→}
   241→
   242→async function main() {
   243→  try {
   244→    // Read input from stdin (required for hook pattern)
   245→    const input = await Bun.stdin.text();
   246→    if (!input || input.trim() === '') {
   247→      process.exit(0);
   248→    }
   249→
   250→    // Check if there's an active work session
   251→    if (!existsSync(CURRENT_WORK_FILE)) {
   252→      console.error('[WorkCompletionLearning] No active work session');
   253→      process.exit(0);
   254→    }
   255→
   256→    // Read current work state
   257→    const currentWork: CurrentWork = JSON.parse(readFileSync(CURRENT_WORK_FILE, 'utf-8'));
   258→
   259→    if (!currentWork.work_dir) {
   260→      console.error('[WorkCompletionLearning] No work directory in current session');
   261→      process.exit(0);
   262→    }
   263→
   264→    // Read work directory metadata
   265→    const workPath = join(WORK_DIR, currentWork.work_dir);
   266→    const metaPath = join(workPath, 'META.yaml');
   267→
   268→    if (!existsSync(metaPath)) {
   269→      console.error('[WorkCompletionLearning] No META.yaml found');
   270→      process.exit(0);
   271→    }
   272→
   273→    const metaContent = readFileSync(metaPath, 'utf-8');
   274→    const workMeta = parseYaml(metaContent);
   275→
   276→    // Update completed_at if not set
   277→    if (!workMeta.completed_at) {
   278→      workMeta.completed_at = getISOTimestamp();
   279→    }
   280→
   281→    // Read ISC.json if it exists
   282→    const iscPath = join(workPath, 'ISC.json');
   283→    let idealContent = '';
   284→    if (existsSync(iscPath)) {
   285→      try {
   286→        const iscData = JSON.parse(readFileSync(iscPath, 'utf-8'));
   287→        // Format ISC for human-readable learning
   288→        if (iscData.current?.criteria?.length > 0) {
   289→          idealContent = '**Criteria:**\n' + iscData.current.criteria.map((c: string) => `- ${c}`).join('\n');
   290→        }
   291→        if (iscData.current?.antiCriteria?.length > 0) {
   292→          idealContent += '\n\n**Anti-Criteria:**\n' + iscData.current.antiCriteria.map((c: string) => `- ${c}`).join('\n');
   293→        }
   294→        if (iscData.satisfaction) {
   295→          const s = iscData.satisfaction;
   296→          idealContent += `\n\n**Satisfaction:** ${s.satisfied}/${s.total} satisfied, ${s.partial} partial, ${s.failed} failed`;
   297→        }
   298→      } catch {
   299→        // Ignore parse errors
   300→      }
   301→    }
   302→
   303→    // Check if this was significant work (has files changed or was manually created)
   304→    const hasSignificantWork = (
   305→      (workMeta.lineage?.files_changed?.length || 0) > 0 ||
   306→      currentWork.item_count > 1 ||
   307→      workMeta.source === 'MANUAL'
   308→    );
   309→
   310→    if (hasSignificantWork) {
   311→      writeLearning(workMeta, idealContent);
   312→    } else {
   313→      console.error('[WorkCompletionLearning] Trivial work session, skipping learning capture');
   314→    }
   315→
   316→    process.exit(0);
   317→  } catch (error) {
   318→    // Silent failure - don't disrupt workflow
   319→    console.error(`[WorkCompletionLearning] Error: ${error}`);
   320→    process.exit(0);
   321→  }
   322→}
   323→
   324→main();
