   444→// UOCS: Capture agent output to history directory
   445→async function captureAgentOutput(
   446→  agentType: string,
   447→  completionMessage: string,
   448→  taskOutput: string,
   449→  transcriptPath: string
   450→) {
   451→  const { writeFileSync, mkdirSync, existsSync } = require('fs');
   452→  const { join } = require('path');
   453→
   454→  const MEMORY_DIR = paiPath('MEMORY');
   455→
   456→  // Generate timestamp for filename (PST)
   457→  const pstTimestamp = getPSTTimestamp();
   458→  const timestamp = pstTimestamp
   459→    .replace(/ PST$/, '')
   460→    .replace(/:/g, '')
   461→    .replace(/ /, '-'); // YYYY-MM-DD-HHMMSS
   462→
   463→  const yearMonth = timestamp.substring(0, 7); // YYYY-MM
   464→
   465→  // Infer capture type from agent type
   466→  // All agent outputs go to RESEARCH for simplicity (consolidated structure)
   467→  let captureType = 'RESEARCH';
   468→  const category = 'RESEARCH';
   469→
   470→  if (agentType === 'researcher' || agentType.includes('researcher')) {
   471→    captureType = 'RESEARCH';
   472→  } else if (agentType === 'architect') {
   473→    captureType = 'DECISION';
   474→  } else if (agentType === 'engineer') {
   475→    captureType = 'IMPLEMENTATION';
   476→  } else if (agentType === 'designer') {
   477→    captureType = 'DESIGN';
   478→  } else if (agentType === 'pentester') {
   479→    captureType = 'SECURITY';
   480→  } else if (agentType === 'intern') {
   481→    captureType = 'RESEARCH';
   482→  }
   483→
   484→  // Generate description from completion message (kebab-case, max 60 chars)
   485→  const description = completionMessage
   486→    .toLowerCase()
   487→    .replace(/^(architect|engineer|designer|researcher|pentester|intern)\s+completed\s+/i, '')
   488→    .replace(/[^a-z0-9]+/g, '-')
   489→    .replace(/^-|-$/g, '')
   490→    .substring(0, 60);
   491→
   492→  // Generate filename
   493→  const filename = `${timestamp}_AGENT-${agentType}_${captureType}_${description}.md`;
   494→
   495→  // Ensure directory exists
   496→  const outputDir = join(MEMORY_DIR, category, yearMonth);
   497→  if (!existsSync(outputDir)) {
   498→    mkdirSync(outputDir, { recursive: true });
   499→  }
   500→
   501→  // Format document
   502→  const fullTimestamp = getPSTTimestamp();
   503→  const document = `---
   504→capture_type: ${captureType}
   505→timestamp: ${fullTimestamp}
   506→executor: ${agentType}
   507→agent_completion: ${completionMessage}
   508→---
   509→
   510→# ${captureType}: ${completionMessage}
   511→
   512→**Agent:** ${agentType}
   513→**Completed:** ${timestamp.replace(/-/g, ':').substring(0, 19)}
   514→
   515→---
   516→
   517→## Agent Output
   518→
   519→${taskOutput}
   520→
   521→---
   522→
   523→## Metadata
   524→
   525→**Transcript:** \`${transcriptPath}\`
   526→**Captured:** ${fullTimestamp}
   527→
   528→---
   529→
   530→*This output was automatically captured by UOCS SubagentStop hook.*
   531→`;
   532→
   533→  // Write file
   534→  const filePath = join(outputDir, filename);
   535→  writeFileSync(filePath, document);
   536→
   537→  console.log(`📝 UOCS: Captured agent output to ${category}/${yearMonth}/${filename}`);
   538→}
   539→
   540→main().catch(console.error);

