     2→/**
     3→ * SessionSummary.hook.ts - Mark Work Complete and Clear State (SessionEnd)
     4→ *
     5→ * PURPOSE:
     6→ * Finalizes a Claude Code session by marking the current work directory as
     7→ * COMPLETED and clearing the session state. This ensures clean session boundaries
     8→ * and accurate work tracking.
     9→ *
    10→ * TRIGGER: SessionEnd
    11→ *
    12→ * INPUT:
    13→ * - stdin: Hook input JSON (session_id, transcript_path)
    14→ * - Files: MEMORY/STATE/current-work.json
    15→ *
    16→ * OUTPUT:
    17→ * - stdout: None
    18→ * - stderr: Status messages
    19→ * - exit(0): Always (non-blocking)
    20→ *
    21→ * SIDE EFFECTS:
    22→ * - Updates: MEMORY/WORK/<dir>/META.yaml (status: COMPLETED, completed_at timestamp)
    23→ * - Deletes: MEMORY/STATE/current-work.json (clears session state)
    24→ *
    25→ * INTER-HOOK RELATIONSHIPS:
    26→ * - DEPENDS ON: AutoWorkCreation (expects WORK/ structure and current-work.json)
    27→ * - COORDINATES WITH: WorkCompletionLearning (both run at SessionEnd)
    28→ * - MUST RUN BEFORE: None (final cleanup)
    29→ * - MUST RUN AFTER: WorkCompletionLearning (learning capture uses state before clear)
    30→ *
    31→ * STATE TRANSITIONS:
    32→ * - META.yaml status: "ACTIVE" → "COMPLETED"
    33→ * - META.yaml completed_at: null → ISO timestamp
    34→ * - current-work.json: exists → deleted
    35→ *
    36→ * DESIGN NOTES:
    37→ * - Does NOT write to SESSIONS/ directory (WORK/ is the primary tracking system)
    38→ * - Deleting current-work.json signals a clean slate for next session
    39→ *
    40→ * ERROR HANDLING:
    41→ * - No current work: Logs message, exits gracefully
    42→ * - Missing META.yaml: Skips update, continues to state clear
    43→ * - File operation failures: Logged to stderr
    44→ *
    45→ * PERFORMANCE:
    46→ * - Non-blocking: Yes
    47→ * - Typical execution: <50ms
    48→ */
    49→
    50→import { writeFileSync, existsSync, readFileSync, unlinkSync } from 'fs';
    51→import { join } from 'path';
    52→import { getISOTimestamp } from './lib/time';
    53→import { getPaiDir } from './lib/paths';
    54→
    55→// Cross-platform path resolution
    56→const PAI_DIR = getPaiDir();
    57→const MEMORY_DIR = join(PAI_DIR, 'MEMORY');
    58→const STATE_DIR = join(MEMORY_DIR, 'STATE');
    59→const CURRENT_WORK_FILE = join(STATE_DIR, 'current-work.json');
    60→const WORK_DIR = join(MEMORY_DIR, 'WORK');
    61→
    62→interface CurrentWork {
    63→  session_id: string;
    64→  work_dir: string;
    65→  created_at: string;
    66→  item_count: number;
    67→}
    68→
    69→/**
    70→ * Mark work directory as completed and clear session state
    71→ */
    72→function clearSessionWork(): void {
    73→  try {
    74→    if (!existsSync(CURRENT_WORK_FILE)) {
    75→      console.error('[SessionSummary] No current work to complete');
    76→      return;
    77→    }
    78→
    79→    // Read current work state
    80→    const content = readFileSync(CURRENT_WORK_FILE, 'utf-8');
    81→    const currentWork: CurrentWork = JSON.parse(content);
    82→
    83→    // Mark work directory as COMPLETED
    84→    if (currentWork.work_dir) {
    85→      const metaPath = join(WORK_DIR, currentWork.work_dir, 'META.yaml');
    86→      if (existsSync(metaPath)) {
    87→        let metaContent = readFileSync(metaPath, 'utf-8');
    88→        metaContent = metaContent.replace(/^status: "ACTIVE"$/m, 'status: "COMPLETED"');
    89→        metaContent = metaContent.replace(/^completed_at: null$/m, `completed_at: "${getISOTimestamp()}"`);
    90→        writeFileSync(metaPath, metaContent, 'utf-8');
    91→        console.error(`[SessionSummary] Marked work directory as COMPLETED: ${currentWork.work_dir}`);
    92→      }
    93→    }
    94→
    95→    // Delete state file
    96→    unlinkSync(CURRENT_WORK_FILE);
    97→    console.error('[SessionSummary] Cleared session work state');
    98→  } catch (error) {
    99→    console.error(`[SessionSummary] Error clearing session work: ${error}`);
   100→  }
   101→}
   102→
   103→async function main() {
   104→  try {
   105→    // Read input from stdin (not strictly needed but matches hook pattern)
   106→    const input = await Bun.stdin.text();
   107→    if (!input || input.trim() === '') {
   108→      process.exit(0);
   109→    }
   110→
   111→    // Mark work as complete and clear state
   112→    // NOTE: Does NOT write to SESSIONS/ - WORK/ is the primary system
   113→    clearSessionWork();
   114→
   115→    console.error('[SessionSummary] Session ended, work marked complete');
   116→    process.exit(0);
   117→  } catch (error) {
   118→    // Silent failure - don't disrupt workflow
   119→    console.error(`[SessionSummary] SessionEnd hook error: ${error}`);
   120→    process.exit(0);
   121→  }
   122→}
   123→
   124→main();
