    47→/**
    48→ * Reset tab title to clean state at session start.
    49→ * Prevents stale tab titles from previous sessions bleeding through.
    50→ * Cross-platform support for Windows Terminal, Kitty, and others.
    51→ */
    52→function resetTabTitle(paiDir: string): void {
    53→  const cleanTitle = 'New Session';
    54→  const stateFile = join(paiDir, 'MEMORY', 'STATE', 'tab-title.json');
    55→
    56→  try {
    57→    const isWindows = process.platform === 'win32';
    58→    const isKitty = process.env.TERM === 'xterm-kitty' || process.env.KITTY_LISTEN_ON;
    59→
    60→    if (isWindows) {
    61→      // Windows Terminal escape sequence
    62→      try {
    63→        const osc = `\x1b]0;${cleanTitle}\x07`;
    64→        process.stdout.write(osc);
    65→        console.error('🔄 Tab title reset (Windows Terminal)');
    66→      } catch (writeError) {
    67→        // Non-critical - tab title is cosmetic
    68→        console.error('🔄 Tab title reset skipped (stdout unavailable on Windows)');
    69→      }
    70→    } else if (isKitty) {
    71→      // Reset Kitty tab title immediately
    72→      execSync(`kitty @ set-tab-title "${cleanTitle}"`, { stdio: 'ignore', timeout: 2000 });
    73→      // Reset tab color to default (dark blue for active, no special color for inactive)
    74→      execSync(
    75→        `kitten @ set-tab-color --self active_bg=#002B80 active_fg=#FFFFFF inactive_bg=none inactive_fg=#A0A0A0`,
    76→        { stdio: 'ignore', timeout: 2000 }
    77→      );
    78→      console.error('🔄 Tab title reset (Kitty)');
    79→    } else {
    80→      // Fallback escape codes for other terminals
    81→      try {
    82→        const osc = `\x1b]0;${cleanTitle}\x07`;
    83→        process.stdout.write(osc);
    84→        console.error('🔄 Tab title reset (fallback)');
    85→      } catch (writeError) {
    86→        // Silent failure - non-critical
    87→        if (process.env.DEBUG_HOOKS === 'true') {
    88→          console.error('🔄 Tab title reset skipped:', writeError);
    89→        }
    90→      }
    91→    }
    92→
    93→    // Reset state file to prevent any stale data
    94→    const cleanState = {
    95→      title: cleanTitle,
    96→      rawTitle: cleanTitle,
    97→      timestamp: new Date().toISOString(),
    98→      state: 'idle'
    99→    };
   100→    writeFileSync(stateFile, JSON.stringify(cleanState, null, 2));
   101→    console.error('🔄 Tab state file reset');
