   205→function loadRelationshipContext(paiDir: string): string | null {
   206→  const parts: string[] = [];
   207→
   208→  // Load high-confidence opinions (>0.85) from OPINIONS.md
   209→  const opinionsPath = join(paiDir, 'skills/PAI/USER/OPINIONS.md');
   210→  if (existsSync(opinionsPath)) {
   211→    try {
   212→      const content = readFileSync(opinionsPath, 'utf-8');
   213→      const highConfidence: string[] = [];
   214→
   215→      // Extract opinions with confidence >= 0.85
   216→      const opinionBlocks = content.split(/^### /gm).slice(1);
   217→      for (const block of opinionBlocks) {
   218→        const lines = block.split('\n');
   219→        const statement = lines[0]?.trim();
   220→        const confidenceMatch = block.match(/\*\*Confidence:\*\*\s*([\d.]+)/);
   221→        const confidence = confidenceMatch ? parseFloat(confidenceMatch[1]) : 0;
   222→
   223→        if (confidence >= 0.85 && statement) {
   224→          highConfidence.push(`• ${statement} (${(confidence * 100).toFixed(0)}%)`);
   225→        }
   226→      }
   227→
   228→      if (highConfidence.length > 0) {
   229→        parts.push('**Key Opinions (high confidence):**');
   230→        parts.push(highConfidence.slice(0, 6).join('\n'));
   231→      }
   232→    } catch (err) {
   233→      console.error(`⚠️ Failed to load opinions: ${err}`);
   234→    }
   235→  }
   236→
   237→  // Load recent relationship notes (today and yesterday)
   238→  const today = new Date();
   239→  const yesterday = new Date(today);
   240→  yesterday.setDate(yesterday.getDate() - 1);
   241→
   242→  const formatDate = (d: Date) => d.toISOString().split('T')[0];
   243→  const formatMonth = (d: Date) => d.toISOString().slice(0, 7);
   244→
   245→  const recentNotes: string[] = [];
   246→  for (const date of [today, yesterday]) {
   247→    const notePath = join(
   248→      paiDir,
   249→      'MEMORY/RELATIONSHIP',
   250→      formatMonth(date),
   251→      `${formatDate(date)}.md`
   252→    );
   253→    if (existsSync(notePath)) {
   254→      try {
   255→        const content = readFileSync(notePath, 'utf-8');
   256→        // Extract just the note lines (starting with -)
   257→        const notes = content
   258→          .split('\n')
   259→          .filter(line => line.trim().startsWith('- '))
   260→          .slice(0, 5); // Last 5 notes per day
   261→        if (notes.length > 0) {
   262→          recentNotes.push(`*${formatDate(date)}:*`);
   263→          recentNotes.push(...notes);
   264→        }
   265→      } catch {}
   266→    }
   267→  }
   268→
   269→  if (recentNotes.length > 0) {
   270→    if (parts.length > 0) parts.push('');
   271→    parts.push('**Recent Relationship Notes:**');
   272→    parts.push(recentNotes.join('\n'));
   273→  }
   274→
   275→  if (parts.length === 0) return null;
   276→
   277→  return `
   278→## Relationship Context
   279→
   280→${parts.join('\n')}
   281→
   282→*Full details: USER/OPINIONS.md, MEMORY/RELATIONSHIP/*
   283→`;
   284→}
