   166→/**
   167→ * Check if prompt is an explicit rating (defer to ExplicitRatingCapture)
   168→ */
   169→function isExplicitRating(prompt: string): boolean {
   170→  const trimmed = prompt.trim();
   171→  const ratingPattern = /^(10|[1-9])(?:\s*[-:]\s*|\s+)?(.*)$/;
   172→  const match = trimmed.match(ratingPattern);
   173→
   174→  if (!match) return false;
   175→
   176→  const comment = match[2]?.trim();
   177→  if (comment) {
   178→    const sentenceStarters = /^(items?|things?|steps?|files?|lines?|bugs?|issues?|errors?|times?|minutes?|hours?|days?|seconds?|percent|%|th\b|st\b|nd\b|rd\b|of\b|in\b|at\b|to\b|the\b|a\b|an\b)/i;
   179→    if (sentenceStarters.test(comment)) {
   180→      return false;
   181→    }
   182→  }
   183→
   184→  return true;
   185→}
