   187→/**
   188→ * Read stdin with timeout
   189→ */
   190→async function readStdinWithTimeout(timeout: number = 5000): Promise<string> {
   191→  return new Promise((resolve, reject) => {
   192→    let data = '';
   193→    const timer = setTimeout(() => reject(new Error('Timeout')), timeout);
   194→    process.stdin.on('data', (chunk) => { data += chunk.toString(); });
   195→    process.stdin.on('end', () => { clearTimeout(timer); resolve(data); });
   196→    process.stdin.on('error', (err) => { clearTimeout(timer); reject(err); });
   197→  });
   198→}
