   200→/**
   201→ * Get recent conversation context from transcript
   202→ */
   203→function getRecentContext(transcriptPath: string, maxTurns: number = 3): string {
   204→  try {
   205→    if (!transcriptPath || !existsSync(transcriptPath)) return '';
   206→
   207→    const content = readFileSync(transcriptPath, 'utf-8');
   208→    const lines = content.trim().split('\n');
   209→
   210→    const turns: { role: string; text: string }[] = [];
   211→
   212→    for (const line of lines) {
   213→      if (!line.trim()) continue;
   214→      try {
   215→        const entry = JSON.parse(line);
   216→
   217→        if (entry.type === 'user' && entry.message?.content) {
   218→          let text = '';
   219→          if (typeof entry.message.content === 'string') {
   220→            text = entry.message.content;
   221→          } else if (Array.isArray(entry.message.content)) {
   222→            text = entry.message.content
   223→              .filter((c: any) => c.type === 'text')
   224→              .map((c: any) => c.text)
   225→              .join(' ');
   226→          }
   227→          if (text.trim()) {
   228→            turns.push({ role: 'User', text: text.slice(0, 200) });
   229→          }
   230→        }
   231→
   232→        if (entry.type === 'assistant' && entry.message?.content) {
   233→          const text = typeof entry.message.content === 'string'
   234→            ? entry.message.content
   235→            : Array.isArray(entry.message.content)
   236→              ? entry.message.content.filter((c: any) => c.type === 'text').map((c: any) => c.text).join(' ')
   237→              : '';
   238→          if (text) {
   239→            const summaryMatch = text.match(/SUMMARY:\s*([^\n]+)/i);
   240→            const shortText = summaryMatch ? summaryMatch[1] : text.slice(0, 150);
   241→            turns.push({ role: 'Assistant', text: shortText });
   242→          }
   243→        }
   244→      } catch {}
   245→    }
   246→
   247→    const recentTurns = turns.slice(-maxTurns);
   248→    if (recentTurns.length === 0) return '';
   249→
   250→    return recentTurns.map(t => `${t.role}: ${t.text}`).join('\n');
   251→  } catch {
   252→    return '';
   253→  }
   254→}
