   256→/**
   257→ * Analyze sentiment using Sonnet
   258→ */
   259→async function analyzeSentiment(prompt: string, context: string): Promise<SentimentResult | null> {
   260→  const userPrompt = context
   261→    ? `CONTEXT:\n${context}\n\nCURRENT MESSAGE:\n${prompt}`
   262→    : prompt;
   263→
   264→  const result = await inference({
   265→    systemPrompt: SENTIMENT_SYSTEM_PROMPT,
   266→    userPrompt,
   267→    expectJson: true,
   268→    timeout: 20000,
   269→    level: 'fast',  // fast = haiku (quick/cheap)
   270→  });
   271→
   272→  if (!result.success || !result.parsed) {
   273→    console.error(`[ImplicitSentimentCapture] Inference failed: ${result.error}`);
   274→    return null;
   275→  }
   276→
   277→  return result.parsed as SentimentResult;
   278→}
