   395→async function main() {
   396→  try {
   397→    console.error('[ImplicitSentimentCapture] Hook started');
   398→    const input = await readStdinWithTimeout();
   399→    const data: HookInput = JSON.parse(input);
   400→    // The payload uses 'prompt' (Claude Code) - user_prompt is legacy
   401→    const prompt = data.prompt || data.user_prompt || '';
   402→
   403→    // Skip if explicit rating (let ExplicitRatingCapture handle)
   404→    if (isExplicitRating(prompt)) {
   405→      console.error('[ImplicitSentimentCapture] Explicit rating detected, deferring to ExplicitRatingCapture');
   406→      process.exit(0);
   407→    }
   408→
   409→    if (prompt.length < MIN_PROMPT_LENGTH) {
   410→      console.error('[ImplicitSentimentCapture] Prompt too short, exiting');
   411→      process.exit(0);
   412→    }
   413→
   414→    const context = getRecentContext(data.transcript_path);
   415→
   416→    const analysisPromise = analyzeSentiment(prompt, context);
   417→    const timeoutPromise = new Promise<null>((resolve) =>
   418→      setTimeout(() => resolve(null), ANALYSIS_TIMEOUT)
   419→    );
   420→
   421→    const sentiment = await Promise.race([analysisPromise, timeoutPromise]);
   422→
   423→    if (!sentiment) {
   424→      console.error('[ImplicitSentimentCapture] Analysis failed or timed out');
   425→      process.exit(0);
   426→    }
   427→
   428→    // Neutral sentiment gets rating 5 (baseline for feature requests)
   429→    if (sentiment.rating === null) {
   430→      sentiment.rating = 5;
   431→      console.error('[ImplicitSentimentCapture] Neutral sentiment, assigning baseline rating 5');
   432→    }
   433→
   434→    if (sentiment.confidence < MIN_CONFIDENCE) {
   435→      console.error(`[ImplicitSentimentCapture] Low confidence (${sentiment.confidence}), not logging`);
   436→      process.exit(0);
   437→    }
   438→
   439→    console.error(`[ImplicitSentimentCapture] Detected: ${sentiment.rating}/10 - ${sentiment.summary}`);
   440→
   441→    const entry: ImplicitRatingEntry = {
   442→      timestamp: getISOTimestamp(),
   443→      rating: sentiment.rating,
   444→      session_id: data.session_id,
   445→      source: 'implicit',
   446→      sentiment_summary: sentiment.summary,
   447→      confidence: sentiment.confidence,
   448→    };
   449→
   450→    writeImplicitRating(entry);
   451→
   452→    // Update trending analysis cache (fire-and-forget, don't block)
   453→    const baseDir = getPaiDir();
   454→    const trendingScript = join(baseDir, 'tools', 'TrendingAnalysis.ts');
   455→    if (existsSync(trendingScript)) {
   456→      Bun.spawn(['bun', trendingScript, '--force'], {
   457→        stdout: 'ignore',
   458→        stderr: 'ignore'
   459→      });
   460→      console.error('[ImplicitSentimentCapture] Triggered TrendingAnalysis update');
   461→    }
   462→
   463→    if (sentiment.rating < 6) {
   464→      captureLowRatingLearning(
   465→        sentiment.rating,
   466→        sentiment.summary,
   467→        sentiment.detailed_context || '',
   468→        data.transcript_path
   469→      );
   470→
   471→      // For ratings 1-3, also create full failure capture
   472→      if (sentiment.rating <= 3) {
   473→        try {
   474→          await captureFailure({
   475→            transcriptPath: data.transcript_path,
   476→            rating: sentiment.rating,
   477→            sentimentSummary: sentiment.summary,
   478→            detailedContext: sentiment.detailed_context || '',
   479→            sessionId: data.session_id,
   480→          });
   481→          console.error(`[ImplicitSentimentCapture] Created full failure capture for rating ${sentiment.rating}`);
   482→        } catch (err) {
   483→          console.error(`[ImplicitSentimentCapture] Error creating failure capture: ${err}`);
   484→        }
   485→      }
   486→    }
   487→
   488→    console.error('[ImplicitSentimentCapture] Done');
   489→    process.exit(0);
   490→  } catch (err) {
   491→    console.error(`[ImplicitSentimentCapture] Error: ${err}`);
   492→    process.exit(0);
   493→  }
   494→}
   495→
   496→main();
