    93→/**
    94→ * CRITICAL: Precise rating detection
    95→ *
    96→ * Must match:
    97→ * - "7" (single number)
    98→ * - "8 - good work" (number + dash + comment)
    99→ * - "6: needs work" (number + colon + comment)
   100→ * - "9 excellent" (number + space + comment)
   101→ *
   102→ * Must NOT match:
   103→ * - "I have 7 items" (number in sentence)
   104→ * - "do step 7" (contextual number)
   105→ * - "7th thing" (ordinal)
   106→ */
   107→function parseRating(prompt: string): { rating: number; comment?: string } | null {
   108→  const trimmed = prompt.trim();
   109→
   110→  // Pattern: Start with single digit (1-10), optionally followed by separator and comment
   111→  const ratingPattern = /^(10|[1-9])(?:\s*[-:]\s*|\s+)?(.*)$/;
   112→
   113→  const match = trimmed.match(ratingPattern);
   114→  if (!match) return null;
   115→
   116→  const rating = parseInt(match[1], 10);
   117→  const comment = match[2]?.trim() || undefined;
   118→
   119→  if (rating < 1 || rating > 10) return null;
   120→
   121→  // Reject if comment starts with common words that indicate a sentence
   122→  if (comment) {
   123→    const sentenceStarters = /^(items?|things?|steps?|files?|lines?|bugs?|issues?|errors?|times?|minutes?|hours?|days?|seconds?|percent|%|th\b|st\b|nd\b|rd\b|of\b|in\b|at\b|to\b|the\b|a\b|an\b)/i;
   124→    if (sentenceStarters.test(comment)) {
   125→      return null;
   126→    }
   127→  }
   128→
   129→  return { rating, comment };
   130→}
