   139→  const ratingsFile = join(signalsDir, 'ratings.jsonl');
   140→
   141→  if (!existsSync(signalsDir)) {
   142→    mkdirSync(signalsDir, { recursive: true });
   143→  }
   144→
   145→  const jsonLine = JSON.stringify(entry) + '\n';
   146→  appendFileSync(ratingsFile, jsonLine, 'utf-8');
   147→
   148→  console.error(`[ExplicitRatingCapture] Wrote rating ${entry.rating} to ${ratingsFile}`);
