   151→/**
   152→ * Extract last response summary from transcript for learning context
   153→ */
   154→function getLastResponseSummary(transcriptPath: string): string {
   155→  try {
   156→    if (!transcriptPath || !existsSync(transcriptPath)) return '';
   157→
   158→    const content = readFileSync(transcriptPath, 'utf-8');
   159→    const lines = content.trim().split('\n');
   160→
   161→    let lastAssistant = '';
   162→    for (const line of lines) {
   163→      try {
   164→        const entry = JSON.parse(line);
   165→        if (entry.type === 'assistant' && entry.message?.content) {
   166→          const text = typeof entry.message.content === 'string'
   167→            ? entry.message.content
   168→            : Array.isArray(entry.message.content)
   169→              ? entry.message.content.filter((c: any) => c.type === 'text').map((c: any) => c.text).join(' ')
   170→              : '';
   171→          if (text) lastAssistant = text;
   172→        }
   173→      } catch { /* skip invalid lines */ }
   174→    }
   175→
   176→    const summaryMatch = lastAssistant.match(/SUMMARY:\s*([^\n]+)/i);
   177→    return summaryMatch ? summaryMatch[1].trim() : lastAssistant.slice(0, 500);
   178→  } catch {
   179→    return '';
   180→  }
   181→}
