   282→      try {
   283→        const osc = `\x1b]0;${truncated}\x07`;
   284→        process.stdout.write(osc);
   285→        console.error(`[UpdateTabTitle] Set title via Windows Terminal escape sequence: "${truncated}"`);
   286→      } catch (writeError) {
