   327→  } catch (err) {
   328→    // Non-blocking error - tab title updates are cosmetic
   329→    console.error(`[UpdateTabTitle] Failed to set tab title: ${err}`);
   330→    console.error(`[UpdateTabTitle] This is non-critical - continuing without tab title update`);
   331→  }
   332→}
   333→
   334→/**
   335→ * Announce prompt receipt via voice server (ElevenLabs TTS).
   336→ * Summary is already a complete sentence from inference.
   337→ */
   338→async function announceVoice(summary: string): Promise<void> {
   339→  const identity = await import('./lib/identity').then(m => m.getIdentity());
   340→
   341→  // Summary is already a complete sentence (e.g., "Fixing the bug now.")
   342→  // Just ensure proper capitalization
   343→  const message = summary.charAt(0).toUpperCase() + summary.slice(1);
   344→
   345→  const voiceId = identity.voiceId || 's3TPKV1kjDlVtZbl4Ksh';
   346→  const voiceSettings = identity.voice;
   347→
   348→  try {
   349→    const response = await fetch('http://localhost:8888/notify', {
   350→      method: 'POST',
   351→      headers: { 'Content-Type': 'application/json' },
   352→      body: JSON.stringify({
   353→        message: message,
   354→        title: `${identity.name} says`,
   355→        voice_enabled: true,
   356→        voice_id: voiceId,
   357→        voice_settings: voiceSettings ? {
   358→          stability: voiceSettings.stability ?? 0.5,
   359→          similarity_boost: voiceSettings.similarity_boost ?? 0.75,
   360→          style: voiceSettings.style ?? 0.0,
   361→          speed: voiceSettings.speed ?? 1.0,
   362→          use_speaker_boost: voiceSettings.use_speaker_boost ?? true,
   363→        } : undefined,
   364→      }),
   365→    });
   366→
   367→    if (!response.ok) {
   368→      console.error('[UpdateTabTitle] Voice server error:', response.statusText);
   369→    } else {
   370→      console.error(`[UpdateTabTitle] Voice sent: "${message}"`);
   371→    }
   372→  } catch (err) {
   373→    console.error('[UpdateTabTitle] Voice failed:', err);
   374→  }
   375→}
   376→
   377→async function main() {
   378→  try {
   379→    console.error('[UpdateTabTitle] Hook started');
   380→    const input = await readStdinWithTimeout();
   381→    const data: HookInput = JSON.parse(input);
   382→    const prompt = data.prompt || '';
   383→    console.error(`[UpdateTabTitle] Prompt: "${prompt.slice(0, 50)}..."`);
   384→
   385→    if (!prompt || prompt.length < 3) {
   386→      console.error('[UpdateTabTitle] Prompt too short, exiting');
   387→      process.exit(0);
   388→    }
   389→
   390→    // Skip ratings (single digit 1-10) - preserve current tab title for the work context
   391→    const trimmedPrompt = prompt.trim();
   392→    if (/^([1-9]|10)$/.test(trimmedPrompt)) {
   393→      console.error(`[UpdateTabTitle] Detected rating input (${trimmedPrompt}), preserving current tab title`);
   394→      process.exit(0);
   395→    }
   396→
   397→    // Set quick fallback title immediately with inference state (purple + "…")
   398→    const quickFallback = quickTitle(prompt);
   399→    console.error(`[UpdateTabTitle] Quick fallback: "${quickFallback}"`);
   400→    setTabTitle(`🧠${quickFallback}`, 'inference');  // Brain = AI thinking/inference
   401→
   402→    // Get summary from Sonnet inference with conversation context
   403→    console.error('[UpdateTabTitle] Calling Sonnet inference...');
   404→    const { summary: rawSummary, fromInference } = await summarizePrompt(prompt, data.transcript_path);
   405→    console.error(`[UpdateTabTitle] Raw summary: "${rawSummary}" (fromInference: ${fromInference})`);
   406→
   407→    // Validate summary - reject garbage, fragments, and generic subjects
   408→    let summary = rawSummary;
   409→    let usedFallback = !fromInference;
   410→
   411→    // Reject summaries that are entirely generic (e.g., "Completing the task.")
   412→    // but allow specific uses like "Fixing task handler." where "task" is part of a specific noun
   413→    const GENERIC_PHRASES = [
   414→      /^completing (the )?task\.?$/i,
   415→      /^working on (the )?(task|request|work)\.?$/i,
   416→      /^processing (the )?(request|task|work)\.?$/i,
   417→      /^handling (the )?(request|task|work)\.?$/i,
   418→      /^finishing (the )?(task|work)\.?$/i,
   419→      /task completion/i,
   420→    ];
   421→    const isGenericSummary = (s: string) => GENERIC_PHRASES.some(p => p.test(s.trim()));
   422→
   423→    if (!isValidTabSummary(rawSummary) || isGenericSummary(rawSummary)) {
   424→      console.error(`[UpdateTabTitle] Invalid or generic summary: "${rawSummary}", using fallback`);
   425→      summary = 'Working on task.';
   426→      usedFallback = true;
   427→    }
   428→
   429→    console.error(`[UpdateTabTitle] Final summary: "${summary}" (fallback: ${usedFallback})`);
   430→
   431→    // Update tab with SHORT title (5 words max - gerund + topic) + working state
   432→    const shortTitle = summary.split(/\s+/).slice(0, 5).join(' ');
   433→    setTabTitle(`⚙️${shortTitle}`, 'working');  // Orange = actively working on task
   434→
   435→    // Voice announcement - speaks the inference-generated summary (e.g., "Checking config")
   436→    // ONLY announce if we got a REAL summary from inference, NOT fallbacks
   437→    if (!usedFallback && isValidTabSummary(shortTitle)) {
   438→      await announceVoice(shortTitle);
   439→      console.error(`[UpdateTabTitle] Voice announced: "${shortTitle}"`);
   440→    } else {
   441→      console.error(`[UpdateTabTitle] Skipped voice - using fallback (fromInference=${fromInference}, usedFallback=${usedFallback})`);
   442→    }
   443→
   444→    console.error('[UpdateTabTitle] Complete');
   445→
   446→    process.exit(0);
   447→  } catch (err) {
   448→    console.error(`[UpdateTabTitle] Error: ${err}`);
   449→    process.exit(0);
   450→  }
   451→}
   452→
   453→main();
