   149→  reason: string;
   150→}
   151→
   152→interface PatternsConfig {
   153→  version: string;
   154→  philosophy: {
   155→    mode: string;
   156→    principle: string;
   157→  };
   158→  bash: {
   159→    blocked: Pattern[];
   160→    confirm: Pattern[];
   161→    alert: Pattern[];
   162→  };
   163→  paths: {
   164→    zeroAccess: string[];
   165→    readOnly: string[];
   166→    confirmWrite: string[];
   167→    noDelete: string[];
