/**
 * project-context.ts - Project-aware memory routing
 *
 * PURPOSE:
 * Detects the current project context and routes memory operations to the
 * appropriate location (project-local or central).
 *
 * ROUTING STRATEGY:
 * - WORK/ → project-local when in project (sessions are project-specific)
 * - RESEARCH/ → project-local when in project (research often project-specific)
 * - LEARNING/SYSTEM/ → always central (system-level learnings)
 * - LEARNING/ALGORITHM/ → always central (universal patterns)
 * - LEARNING/SIGNALS/ → always central (AI performance tracking)
 * - LEARNING/FAILURES/ → always central (cross-project learning)
 * - LEARNING/{category} → central for system/algorithm, project-local for project-specific
 * - STATE/ → always central (runtime state)
 * - SECURITY/ → always central (security events)
 * - RELATIONSHIP/ → always central (relationship is personal, not project-specific)
 *
 * PROJECT DETECTION:
 * 1. Check if CWD is within ~/Projects/* (user's project root)
 * 2. Check for .pai-root marker file (walks up tree)
 * 3. Check if CWD contains a .git directory (project indicator)
 * 4. Fall back to central mode
 */

import { existsSync } from 'fs';
import { join, dirname, basename } from 'path';
import { homedir } from 'os';
import { getPaiDir } from './paths';

// ============================================================================
// Types
// ============================================================================

export interface ProjectInfo {
  name: string;
  rootPath: string;
  memoryPath: string;
  isPAIProject: boolean;
}

export interface MemoryPaths {
  // Central paths (always go to ~/.claude/MEMORY)
  central: {
    base: string;
    learning: {
      system: string;
      algorithm: string;
      signals: string;
      failures: string;
    };
    state: string;
    security: string;
    relationship: string;
  };
  // Project paths (conditional)
  project: {
    base: string | null;
    work: string | null;
    research: string | null;
    learning: {
      project: string | null;
    } | null;
  } | null;
}

// ============================================================================
// Project Detection
// ============================================================================

/**
 * Maximum iterations when walking up directory tree
 */
const MAX_TREE_WALK = 20;

/**
 * Detect if we're in a project directory
 */
export function detectProject(): ProjectInfo | null {
  const cwd = process.cwd();

  // Check if we're in PAI's own directory (always use central mode)
  const paiDir = getPaiDir();
  if (cwd.includes('.claude') || cwd === paiDir) {
    return null;
  }

  // Method 1: Check if in ~/Projects/* (common convention)
  const projectsRoot = join(homedir(), 'Projects');
  if (cwd.startsWith(projectsRoot) && cwd !== projectsRoot) {
    const projectName = basename(cwd);
    return {
      name: projectName,
      rootPath: cwd,
      memoryPath: join(cwd, '.pai-memory'),
      isPAIProject: false
    };
  }

  // Method 2: Walk up tree looking for .pai-root marker
  let current = cwd;
  let iterations = 0;
  while (current !== homedir() && iterations < MAX_TREE_WALK) {
    const markerPath = join(current, '.pai-root');
    if (existsSync(markerPath)) {
      return {
        name: basename(current),
        rootPath: current,
        memoryPath: join(current, '.pai-memory'),
        isPAIProject: false
      };
    }
    current = dirname(current);
    iterations++;
  }

  // Method 3: Check for .git directory (common project indicator)
  current = cwd;
  iterations = 0;
  while (current !== homedir() && iterations < MAX_TREE_WALK) {
    const gitPath = join(current, '.git');
    if (existsSync(gitPath)) {
      return {
        name: basename(current),
        rootPath: current,
        memoryPath: join(current, '.pai-memory'),
        isPAIProject: false
      };
    }
    current = dirname(current);
    iterations++;
  }

  // No project detected - use central mode
  return null;
}

// ============================================================================
// Path Resolution
// ============================================================================

/**
 * Get memory paths based on current context
 * Returns both central paths (always available) and project paths (conditional)
 */
export function getMemoryPaths(): MemoryPaths {
  const paiDir = getPaiDir();
  const project = detectProject();

  const centralBase = join(paiDir, 'MEMORY');

  const result: MemoryPaths = {
    central: {
      base: centralBase,
      learning: {
        system: join(centralBase, 'LEARNING', 'SYSTEM'),
        algorithm: join(centralBase, 'LEARNING', 'ALGORITHM'),
        signals: join(centralBase, 'LEARNING', 'SIGNALS'),
        failures: join(centralBase, 'LEARNING', 'FAILURES'),
      },
      state: join(centralBase, 'STATE'),
      security: join(centralBase, 'SECURITY'),
      relationship: join(centralBase, 'RELATIONSHIP'),
    },
    project: null
  };

  if (project) {
    const projectBase = project.memoryPath;
    result.project = {
      base: projectBase,
      work: join(projectBase, 'WORK'),
      research: join(projectBase, 'RESEARCH'),
      learning: {
        project: join(projectBase, 'LEARNING'),
      }
    };
  }

  return result;
}

/**
 * Get the appropriate directory for WORK/ files
 * - In project: project-local
 * - Outside project: central
 */
export function getWorkDir(): string {
  const paths = getMemoryPaths();
  return paths.project?.work || paths.central.base + '/WORK';
}

/**
 * Get the appropriate directory for RESEARCH/ files
 * - In project: project-local
 * - Outside project: central
 */
export function getResearchDir(): string {
  const paths = getMemoryPaths();
  return paths.project?.research || paths.central.base + '/RESEARCH';
}

/**
 * Get the appropriate directory for LEARNING/ files
 * - SYSTEM/ALGORITHM/SIGNALS/FAILURES: always central
 * - Other categories: project-local if in project
 */
export function getLearningDir(category: string): string {
  const paths = getMemoryPaths();

  // System-level categories always go central
  const centralCategories = ['SYSTEM', 'ALGORITHM', 'SIGNALS', 'FAILURES'];
  if (centralCategories.includes(category.toUpperCase())) {
    return join(paths.central.base, 'LEARNING', category);
  }

  // Project-local if available
  return paths.project?.learning?.project
    ? join(paths.project.learning.project, category)
    : join(paths.central.base, 'LEARNING', category);
}

/**
 * Get STATE directory (always central)
 */
export function getStateDir(): string {
  return getMemoryPaths().central.state;
}

/**
 * Get SECURITY directory (always central)
 */
export function getSecurityDir(): string {
  return getMemoryPaths().central.security;
}

/**
 * Get RELATIONSHIP directory (always central)
 */
export function getRelationshipDir(): string {
  return getMemoryPaths().central.relationship;
}

// ============================================================================
// Utility Functions
// ============================================================================

/**
 * Get a descriptive string of current context for logging
 */
export function getContextDescription(): string {
  const project = detectProject();
  if (project) {
    return `Project: ${project.name} (${project.rootPath})`;
  }
  return 'Central (no project detected)';
}

// ============================================================================
// Exports
// ============================================================================

export default {
  detectProject,
  getMemoryPaths,
  getWorkDir,
  getResearchDir,
  getLearningDir,
  getStateDir,
  getSecurityDir,
  getRelationshipDir,
  getContextDescription,
};

